import React, { useState } from 'react';
import { Bell, Menu, Moon, Sun, User } from 'lucide-react-native';
import { Link } from 'react-router-dom';

const Navbar = () => {
  const [isOpen, setIsOpen] = useState(false);
  const [isDarkMode, setIsDarkMode] = useState(false);

  const toggleMenu = () => {
    setIsOpen(!isOpen);
  };

  const toggleDarkMode = () => {
    setIsDarkMode(!isDarkMode);
  };

  return (
    <nav className="bg-zinc-600 text-zinc-400 py-6 md:py-8 lg:py-10 sticky top-0 z-50 transition-all duration-300">
      <div className="container mx-auto flex justify-between items-center">
        <Link to="/" className="text-lg font-bold text-zinc-400 hover:text-zinc-200 transition-all duration-300">
          TechHub
        </Link>
        <button
          className="lg:hidden flex justify-center w-8 h-8 bg-zinc-600 hover:bg-zinc-700 rounded-md transition-all duration-300"
          onClick={toggleMenu}
        >
          <Menu size={24} color="#94a3b8" aria-label="Menu" />
        </button>
        <ul
          className={`lg:flex lg:items-center lg:justify-between lg:space-x-4 ${isOpen ? 'block' : 'hidden'
            } md:w-1/2 lg:w-auto lg:space-x-8 lg:py-0 lg:mx-0 mx-4 py-4 lg:mt-0 mt-4 bg-zinc-600 lg:bg-transparent lg:shadow-none shadow-md lg:rounded-none rounded-md transition-all duration-300`}
        >
          <li>
            <Link to="/" className="text-zinc-400 hover:text-zinc-200 transition-all duration-300">
              Home
            </Link>
          </li>
          <li>
            <Link to="/about" className="text-zinc-400 hover:text-zinc-200 transition-all duration-300">
              About
            </Link>
          </li>
          <li>
            <Link to="/contact" className="text-zinc-400 hover:text-zinc-200 transition-all duration-300">
              Contact
            </Link>
          </li>
        </ul>
        <div className="hidden lg:flex items-center space-x-4">
          <button
            className="flex justify-center w-8 h-8 bg-zinc-600 hover:bg-zinc-700 rounded-md transition-all duration-300"
            onClick={toggleDarkMode}
          >
            {isDarkMode ? <Sun size={24} color="#94a3b8" aria-label="Light Mode" /> : <Moon size={24} color="#94a3b8" aria-label="Dark Mode" />}
          </button>
          <button
            className="flex justify-center w-8 h-8 bg-zinc-600 hover:bg-zinc-700 rounded-md transition-all duration-300"
          >
            <Bell size={24} color="#94a3b8" aria-label="Notifications" />
          </button>
          <button
            className="flex justify-center w-8 h-8 bg-zinc-600 hover:bg-zinc-700 rounded-md transition-all duration-300"
          >
            <User size={24} color="#94a3b8" aria-label="User" />
          </button>
        </div>
      </div>
    </nav>
  );
};

export default Navbar;

