import React, { useState } from 'react';
import { ArrowDown } from 'lucide-react-native';

const HeroSection = () => {
  const [isHovered, setIsHovered] = useState(false);

  return (
    <section className="h-screen bg-zinc-600 flex flex-col justify-center items-center pt-12 md:pt-16 lg:pt-20">
      <h1 className="text-5xl text-white font-bold font-dm-sans mb-4 sm:mb-6 md:mb-8 lg:mb-10 transition-all duration-300">
        TechHub
      </h1>
      <p className="text-2xl text-zinc-400 font-dm-sans mb-8 sm:mb-10 md:mb-12 lg:mb-14 transition-all duration-300">
        Innovative Technology Solutions at Your Fingertips
      </p>
      <button
        className={`bg-zinc-700 hover:bg-zinc-800 text-white font-dm-sans py-3 px-6 rounded-md transition-all duration-300 ${isHovered ? 'shadow-md' : 'shadow-none'}`}
        onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => setIsHovered(false)}
      >
        Explore More
      </button>
      <div className="mt-10 sm:mt-12 md:mt-14 lg:mt-16">
        <ArrowDown size={24} color="#fff" aria-label="Scroll Down" />
      </div>
    </section>
  );
};

export default HeroSection;

