import React, { useState } from 'react';
import { ArrowRight } from 'lucide-react-native';
import { Link } from 'react-router-dom';

const FeaturedProducts = () => {
  const [activeTab, setActiveTab] = useState('tab1');
  const tabs = [
    { id: 'tab1', title: 'New Arrivals' },
    { id: 'tab2', title: 'Best Sellers' },
    { id: 'tab3', title: 'Top Rated' },
  ];

  const handleTabChange = (tabId) => {
    setActiveTab(tabId);
  };

  return (
    <div className="container mx-auto p-6 md:p-8 lg:p-12">
      <h2 className="text-3xl text-zinc-400 font-bold mb-6 md:mb-8 lg:mb-10 transition-all duration-300">
        Featured Products
      </h2>
      <div className="flex flex-wrap justify-center mb-6 md:mb-8 lg:mb-10">
        {tabs.map((tab) => (
          <button
            key={tab.id}
            onClick={() => handleTabChange(tab.id)}
            className={`py-2 px-4 md:px-6 lg:px-8 text-zinc-400 hover:text-white hover:bg-zinc-700 rounded-md md:rounded-lg lg:rounded-xl transition-all duration-300 ${
              activeTab === tab.id ? 'bg-zinc-600' : 'bg-transparent'
            }`}
          >
            {tab.title}
          </button>
        ))}
      </div>
      <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-6 md:gap-8 lg:gap-10">
        {[1, 2, 3, 4, 5, 6, 7, 8].map((item) => (
          <div
            key={item}
            className="bg-zinc-800 rounded-md md:rounded-lg lg:rounded-xl p-6 md:p-8 lg:p-10 hover:bg-zinc-700 transition duration-300"
          >
            <h3 className="text-2xl text-zinc-400 font-bold mb-4 md:mb-6 lg:mb-8 transition-all duration-300">
              Product {item}
            </h3>
            <p className="text-zinc-500 mb-6 md:mb-8 lg:mb-10 transition-all duration-300">
              Lorem ipsum dolor sit amet, consectetur adipiscing elit.
            </p>
            <Link
              to="/product"
              className="flex items-center text-zinc-400 hover:text-white hover:bg-zinc-700 py-2 px-4 md:px-6 lg:px-8 rounded-md md:rounded-lg lg:rounded-xl transition-all duration-300"
            >
              View Details <ArrowRight size={20} className="ml-2" aria-label="View Details" />
            </Link>
          </div>
        ))}
      </div>
    </div>
  );
};

export default FeaturedProducts;

